import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

const ClientDashboard = () => {
  const navigate  = useNavigate();
  const user      = JSON.parse(localStorage.getItem("user") || "{}");
  const [projects,   setProjects]   = useState([]);
  const [proposals,  setProposals]  = useState([]);
  const [loading,    setLoading]    = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const projRes = await API.get("/projects/client");
        const data    = projRes.data || [];
        setProjects(data);

        // Fetch proposals for all projects
        const allProposals = [];
        await Promise.all(data.map(async (p) => {
          try {
            const r = await API.get(`/proposals/project/${p.id}`);
            (r.data || []).forEach(pr => allProposals.push(pr));
          } catch {}
        }));
        setProposals(allProposals);
      } catch (err) { console.error(err); }
      setLoading(false);
    };
    load();
  }, []);

  // ✅ Real computed stats
  const totalProjects    = projects.length;
  const openProjects     = projects.filter(p => !p.status || p.status === "open").length;
  const totalProposals   = proposals.length;
  const acceptedProposals = proposals.filter(p => p.status === "accepted").length;

  const formatDate = (d) => d ? new Date(d).toLocaleDateString("en-IN", {
    day: "2-digit", month: "short", year: "numeric"
  }) : "";

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-5xl mx-auto">

        {/* HEADER */}
        <div className="flex justify-between items-center mb-8">
          <div>
            <h1 className="text-2xl font-bold text-gray-800">Client Dashboard</h1>
            <p className="text-gray-500 text-sm">Welcome back, {user.name} 👋</p>
          </div>
          <button onClick={() => navigate("/client/post-project")}
            className="bg-teal-600 hover:bg-teal-700 text-white px-5 py-2 rounded-lg text-sm font-medium transition">
            + Post New Project
          </button>
        </div>

        {/* STAT CARDS */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
          <div className="bg-white rounded-xl p-5 shadow-sm border border-gray-100">
            <p className="text-xs text-gray-500 mb-1">Total Projects</p>
            <h2 className="text-3xl font-bold text-teal-600">{totalProjects}</h2>
          </div>
          <div className="bg-white rounded-xl p-5 shadow-sm border border-gray-100">
            <p className="text-xs text-gray-500 mb-1">Open Projects</p>
            <h2 className="text-3xl font-bold text-blue-600">{openProjects}</h2>
          </div>
          <div className="bg-white rounded-xl p-5 shadow-sm border border-gray-100">
            <p className="text-xs text-gray-500 mb-1">Total Proposals</p>
            <h2 className="text-3xl font-bold text-yellow-600">{totalProposals}</h2>
          </div>
          <div className="bg-white rounded-xl p-5 shadow-sm border border-gray-100">
            <p className="text-xs text-gray-500 mb-1">Hired Freelancers</p>
            <h2 className="text-3xl font-bold text-green-600">{acceptedProposals}</h2>
          </div>
        </div>

        {/* RECENT PROJECTS */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-center p-5 border-b border-gray-100">
            <h2 className="font-bold text-gray-700">Recent Projects</h2>
            <button onClick={() => navigate("/client/my-projects")}
              className="text-sm text-teal-600 hover:text-teal-700 font-medium">
              View All →
            </button>
          </div>

          {projects.length === 0 ? (
            <div className="text-center py-12">
              <div className="text-4xl mb-3">📁</div>
              <p className="text-gray-400 mb-4">No projects yet.</p>
              <button onClick={() => navigate("/client/post-project")}
                className="bg-teal-600 text-white px-5 py-2 rounded-lg text-sm font-medium">
                Post Your First Project
              </button>
            </div>
          ) : (
            <div className="divide-y divide-gray-50">
              {projects.slice(0, 5).map((p) => {
                const projProposals = proposals.filter(pr => pr.project_id === p.id);
                const accepted      = projProposals.find(pr => pr.status === "accepted");
                return (
                  <div key={p.id} className="flex justify-between items-center px-5 py-4 hover:bg-gray-50 transition">
                    <div className="flex-1 min-w-0">
                      <h3 className="font-semibold text-gray-800 truncate">{p.title}</h3>
                      <div className="flex gap-4 text-xs text-gray-400 mt-1">
                        <span>💰 ₹{p.budget}</span>
                        {p.deadline && <span>📅 {formatDate(p.deadline)}</span>}
                        <span>📄 {projProposals.length} proposal{projProposals.length !== 1 ? "s" : ""}</span>
                        {accepted && (
                          <span className="text-green-600 font-medium">✅ {accepted.freelancer_name} hired</span>
                        )}
                      </div>
                    </div>
                    <div className="flex items-center gap-3 ml-4">
                      <span className={`px-2 py-0.5 rounded-full text-xs font-semibold capitalize ${
                        p.status === "closed"     ? "bg-red-100 text-red-600" :
                        p.status === "completed"  ? "bg-blue-100 text-blue-600" :
                        "bg-green-100 text-green-600"
                      }`}>{p.status || "Open"}</span>
                      <button onClick={() => navigate(`/client/projects/${p.id}/proposals`)}
                        className="text-xs bg-teal-50 hover:bg-teal-100 text-teal-700 px-3 py-1 rounded-lg border border-teal-200 transition">
                        Proposals →
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export default ClientDashboard;
